using System;
using System.Collections.Generic;
using System.Net.Http;
using System.Net.Http.Headers;
using System.Text;
using System.Threading.Tasks;
using UnityEngine;

public class TwitchFollowEvents
{
    private readonly string clientId;
    private readonly string clientSecret;
    private readonly string callbackUrl;
    private readonly string twitchApiBaseUrl = "https://api.twitch.tv/helix";

    private string userAccessToken;

    public TwitchFollowEvents(string clientId, string clientSecret, string callbackUrl)
    {
        this.clientId = clientId;
        this.clientSecret = clientSecret;
        this.callbackUrl = callbackUrl;
    }

    public async Task SubscribeToFollowEvents(string userId, string userAccessToken)
    {
        this.userAccessToken = userAccessToken;

        // Register a webhook for follow events
        string topicUrl = $"{twitchApiBaseUrl}/eventsub/subscriptions";
        string topicType = "channel.follow";
        string callbackUrl = this.callbackUrl;
        Dictionary<string, string> eventData = new Dictionary<string, string>()
        {
            { "broadcaster_user_id", userId }
        };

        string subscriptionId = await RegisterSubscription(topicUrl, topicType, callbackUrl, eventData);

        Debug.Log($"Follow event subscription created with subscription ID: {subscriptionId}");
    }

    private async Task<string> RegisterSubscription(string topicUrl, string topicType, string callbackUrl, Dictionary<string, string> eventData)
    {
        using (var httpClient = new HttpClient())
        {
            httpClient.DefaultRequestHeaders.Authorization = new AuthenticationHeaderValue("Bearer", userAccessToken);
            httpClient.DefaultRequestHeaders.Add("Client-ID", clientId);

            // Create a subscription request
            var subscriptionRequest = new
            {
                type = topicType,
                version = "1",
                condition = eventData,
                transport = new
                {
                    method = "webhook",
                    callback = callbackUrl,
                    secret = Guid.NewGuid().ToString()
                }
            };

            var content = new StringContent(JsonUtility.ToJson(subscriptionRequest), Encoding.UTF8, "application/json");
            var response = await httpClient.PostAsync(topicUrl, content);

            if (response.IsSuccessStatusCode)
            {
                // Get the subscription ID from the response headers
                string subscriptionId = response.Headers.GetValues("Twitch-Eventsub-Subscription-Id").ToString();

                return subscriptionId;
            }
            else
            {
                throw new Exception($"Failed to register Twitch subscription: {response.StatusCode} - {await response.Content.ReadAsStringAsync()}");
            }
        }
    }
}
