// Function to calculate the cost of being at pose x_t
double costFunction(const geometry_msgs::Pose& x_t, const geometry_msgs::Pose& x_g, double w_d, double w_obs)
{
  // Calculate Euclidean distance between x_t and x_g
  double dx = x_t.position.x - x_g.position.x;
  double dy = x_t.position.y - x_g.position.y;
  double d_theta = std::atan2(std::sin(x_t.orientation.z - x_g.orientation.z), std::cos(x_t.orientation.z - x_g.orientation.z));
  double dist_to_goal = std::sqrt(dx*dx + dy*dy + d_theta*d_theta);

  // Get cost of being at x_t from costmap
  int index = (x_t.position.y - costmap->info.origin.position.y) / costmap->info.resolution * costmap->info.width +
              (x_t.position.x - costmap->info.origin.position.x) / costmap->info.resolution;
  double cost_obs = costmap->data[index];

  // Calculate total cost using weighted sum
  double total_cost = w_d * dist_to_goal + w_obs * cost_obs;

  return total_cost;
}

