To implement a linked list in Rust without using the standard library, you can use a combination of enums and references to create a data structure that stores a sequence of values. Here's an example of how you might implement a singly-linked list:
```
// A node in the linked list.
struct Node<T> {
    // The value stored in the node.
    value: T,

    // The next node in the list, or `None` if this is the last node.
    next: Option<&Node<T>>,
}

// The linked list itself.
struct List<T> {
    // The first node in the list, or `None` if the list is empty.
    head: Option<&Node<T>>,
}

impl<T> List<T> {
    // Creates a new, empty linked list.
    fn new() -> Self {
        List { head: None }
    }

    // Adds a new value to the front of the list.
    fn push(&mut self, value: T) {
        let node = Node {
            value: value,
            next: self.head,
        };
        self.head = Some(&node);
    }

    // Removes the first value from the list and returns it, or `None` if the list is empty.
    fn pop(&mut self) -> Option<T> {
        match self.head {
            Some(node) => {
                self.head = node.next;
                Some(node.value)
            }
            None => None,
        }
    }
}
