## 📜 Script File: `measure-traffic.js`

This script uses **Puppeteer** to launch a headless Chrome browser, navigate to the given URL, and collect network traffic data.

```javascript
const puppeteer = require('puppeteer');
const url = process.argv[2]; // Get the URL from command line

(async () => {
  try {
    // Launch browser
    const browser = await puppeteer.launch({
      headless: true,
      args: ['--no-sandbox', '--disable-setuid-sandbox'],
    });

    const page = await browser.newPage();

    // Listen for network events
    const assetTypes = {
      'document': 'HTML',
      'stylesheet': 'CSS',
      'script': 'JS',
      'image': 'Images',
      'font': 'Fonts',
      'media': 'Media',
      'other': 'Other',
    };

    const trafficStats = {};

    page.on('request', (request) => {
      const type = request.resourceType();
      if (!trafficStats[type]) {
        trafficStats[type] = { count: 0, size: 0 };
      }
      trafficStats[type].count += 1;
      trafficStats[type].size += request.resourceType().length;
    });

    page.on('response', (response) => {
      const type = response.request().resourceType();
      if (!trafficStats[type]) {
        trafficStats[type] = { count: 0, size: 0 };
      }
      trafficStats[type].count += 1;
      trafficStats[type].size += response.headers()['content-length'] || 0;
    });

    await page.goto(url, { waitUntil: 'networkidle2' });

    await browser.close();

    // Format the results
    const formattedStats = {};
    for (const [type, data] of Object.entries(trafficStats)) {
      const category = assetTypes[type] || 'Other';
      formattedStats[category] = {
        count: data.count,
        size: data.size,
      };
    }

    console.log(JSON.stringify(formattedStats, null, 2));
  } catch (err) {
    console.error('Error occurred:', err);
  }
})();
```

