### ✅ `UploadFCSFiles.tsx`

```tsx
import React, { useState } from 'react';
import { useDropzone } from 'react-dropzone';
import { BlobServiceClient } from '@azure/storage-blob';

// Replace with your SAS URL (make sure it's a public container with write access)
const SAS_URL = 'https://<storage-account-name>.blob.core.windows.net/<container-name>?<sas-token>';

// Replace with your container name
const CONTAINER_NAME = 'fcs-uploads';

// Blob service client
const blobServiceClient = BlobServiceClient.fromBlobUrl(SAS_URL);

// Create a container if it doesn't exist
const containerClient = blobServiceClient.getContainerClient(CONTAINER_NAME);

const UploadFCSFiles: React.FC = () => {
  const [files, setFiles] = useState<string[]>([]);

  const onDrop = async (acceptedFiles: File[]) => {
    const filePromises = acceptedFiles.map(async (file) => {
      const blockBlobClient = containerClient.getBlockBlobClient(file.name);

      try {
        await blockBlobClient.uploadBrowserData(file);
        const blobUrl = await blockBlobClient.url;
        setFiles((prev) => [...prev, blobUrl]);
        return blobUrl;
      } catch (error) {
        console.error(`Failed to upload ${file.name}:`, error);
        return null;
      }
    });

    await Promise.all(filePromises);
  };

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    accept: {
      'application/fcs': ['.fcs'],
    },
  });

  return (
    <div>
      <div {...getRootProps()}>
        <input {...getInputProps()} />
        <p>Drag & drop FCS files here, or click to select files</p>
        {isDragActive ? (
          <p>✅ File(s) are being dragged</p>
        ) : (
          <p>📁 Drop FCS files here to upload</p>
        )}
      </div>

      <h3>Uploaded Files</h3>
      <ul>
        {files.map((url, index) => (
          <li key={index}>
            <a href={url} target="_blank" rel="noopener noreferrer">
              {url}
            </a>
          </li>
        ))}
      </ul>
    </div>
  );
};

export default UploadFCSFiles;
```

---

### 📌 Notes & Tips

- **SAS URL**: The SAS URL must allow write access to the container. You can generate one using the Azure portal or Azure CLI.
- **SAS URL Format**: You can use this format:
  ```
  https://<storage-account-name>.blob.core.windows.net/<container-name>?<sas-token>
  ```
- **File Name**: Make sure the file names are unique to avoid overwriting.
- **Security**: Never expose your storage account key directly in the client. Use a SAS token instead.
- **Browser Support**: `uploadBrowserData()` is supported in modern browsers.

---

### 🧠 Why this works

- **Direct Upload**: Avoids server-side processing and reduces load on your Next.js app.
- **Efficient**: Files go from client to Azure Blob Storage directly.
- **Scalable**: Handles large numbers of files and large files.

---

