private static boolean solve(SudokuBoard board) {
    int row = -1, col = -1;
    for (int i = 0; i < 9; i++) {
        for (int j = 0; j < 9; j++) {
            if (board.get(i, j) == 0) {
                row = i;
                col = j;
                break;
            }
        }
        if (row != -1) break;
    }

    if (row == -1) {
        // Board is solved
        return true;
    }

    for (int num = 1; num <= 9; num++) {
        if (isSafe(board, row, col, num)) {
            board.set(row, col, num);
            if (solve(board)) {
                return true;
            }
            board.set(row, col, 0); // Backtrack
        }
    }

    return false; // No solution found
}

private static boolean isSafe(SudokuBoard board, int row, int col, int num) {
    // Check row
    for (int i = 0; i < 9; i++) {
        if (board.get(row, i) == num) return false;
    }

    // Check column
    for (int i = 0; i < 9; i++) {
        if (board.get(i, col) == num) return false;
