// Create an array of questions and answers
const questions = [
  {
    question: "What is the capital of France?",
    choices: ["Paris", "London", "Rome", "Madrid"],
    answer: "Paris"
  },
  {
    question: "What is the largest planet in our solar system?",
    choices: ["Earth", "Mars", "Jupiter", "Saturn"],
    answer: "Jupiter"
  },
