// Function to render the question and choices to the page
function renderQuestion() {
  // Get the current question
  const current = questions[currentQuestion];

  // Get the element to display the question
  const questionEl = document.getElementById("question");
  questionEl.textContent = current.question;

  // Get the element to display the choices
  const choicesEl = document.getElementById("choices");
  choicesEl.innerHTML = "";

  // Loop through the choices and create a radio button for each one
  for (let choice of current.choices) {
    const choiceEl = document.createElement("input");
    choiceEl.type = "radio";
    choiceEl.name = "choice";
    choiceEl.value = choice;
    choicesEl.appendChild(choiceEl);

    const choiceLabelEl = document.createElement("label");
    choiceLabelEl.textContent = choice;
    choicesEl.appendChild(choiceLabelEl);
  }
}

// Function to move to the next question
function nextQuestion() {
  // Get the selected choice
  const choice = document.querySelector('input[name="choice"]:checked');

  // Check if a choice was selected
  if (choice) {
    // Check if the selected choice is the correct answer
    if (choice.value === questions[currentQuestion].answer) {
      // Increment the score
      score++;
    }

    // Move to the next question
    currentQuestion++;

    // Check if there are more questions
    if (currentQuestion < questions.length) {
      // Render the next question
      renderQuestion();
    } else {
      // Show the score
      alert(`Your score is ${score}/${questions.length}`);
    }
  } else {
    // No choice was selected, show an error message
    alert("Please select a choice");
  }
}

// Render the initial question
renderQuestion();
