The Single Responsibility Principle is a principle of object-oriented programming that states that a class should have only one reason to change. This means that a class should have a single, well-defined responsibility, and that responsibility should be entirely encapsulated by the class.

Here is an example of the Single Responsibility Principle in TypeScript:
```
// This is a class that represents a user account
class Account {
  // The account has a username and a password
  private username: string;
  private password: string;

  // The constructor takes the username and password as arguments
  constructor(username: string, password: string) {
    this.username = username;
    this.password = password;
  }

  // This method verifies that the given password is correct
  public verifyPassword(password: string): boolean {
    return password === this.password;
  }
}

// This is a class that represents a user profile
class Profile {
  // The profile has a user name and an email address
  private username: string;
  private email: string;

  // The constructor takes the username and email as arguments
  constructor(username: string, email: string) {
    this.username = username;
    this.email = email;
  }

  // This method returns the username
  public getUsername(): string {
    return this.username;
  }

  // This method returns the email address
  public getEmail(): string {
    return this.email;
  }
}

// This is a class that represents a user session
class Session {
  // The session has an account and a profile
  private account: Account;
  private profile: Profile;

  // The constructor takes the account and profile as arguments
  constructor(account: Account, profile: Profile) {
    this.account = account;
    this.profile = profile;
  }

  // This method returns the user name
  public getUsername(): string {
    return this.profile.getUsername();
  }

  // This method returns the email address
  public getEmail(): string {
    return this.profile.getEmail();
  }

  // This method verifies that the given password is correct
  public verifyPassword(password: string): boolean {
    return this.account.verifyPassword(password);
  }
}

// Now we can create an instance of the Session class
