namespace App\Http\Controllers;

use Illuminate\Http\Request;
use Illuminate\Support\Facades\Http;
use App\Models\ApiKey;

class ApiKeyController extends Controller
{
    public function index()
    {
        $apiKey = ApiKey::first();
        return view('apiKey', compact('apiKey'));
    }

    public function store(Request $request)
    {
        $request->validate([
            'api_key' => 'required|string',
        ]);

        $response = Http::withHeaders([
            'X-MailerLite-ApiKey' => $request->api_key,
        ])->get('https://api.mailerlite.com/api/v2/me');

        if ($response->successful()) {
            $apiKey = ApiKey::first() ?: new ApiKey();
            $apiKey->key = $request->api_key;
            $apiKey->save();

            return redirect()->route('api-key')->with('success', 'API key saved successfully.');
        } else {
            return redirect()->route('api-key')->with('error', 'Invalid API key.');
        }
    }
}
