```php
namespace App\Http\Controllers;

use Illuminate\Http\Request;
use Illuminate\Support\Facades\Http;
use App\Models\Subscriber;
use App\Models\ApiKey;

class SubscriberController extends Controller
{
    public function index(Request $request)
    {
        $apiKey = ApiKey::first();

        $response = Http::withHeaders([
            'X-MailerLite-ApiKey' => $apiKey->key,
        ])->get('https://api.mailerlite.com/api/v2/subscribers');

        $subscribers = $response->json()['data'];

        return view('subscribers', compact('subscribers', 'apiKey'));
    }

    public function store(Request $request)
    {
        $request->validate([
            'email' => 'required|email|unique:subscribers,email',
            'name' => 'nullable|string',
            'country' => 'nullable|string',
        ]);

        $apiKey = ApiKey::first();

        $response = Http::withHeaders([
            'X-MailerLite-ApiKey' => $apiKey->key,
        ])->post('https://api.mailerlite.com/api/v2/subscribers', [
            'email' => $request->email,
            'name' => $request->name,
            'country' => $request->country,
        ]);

        if ($response->successful()) {
            $subscriber = $response->json()['data'];
            Subscriber::create([
                'email' => $subscriber['email'],
                'name' => $subscriber['name'],
                'country' => $subscriber['country'],
                'subscribe_date' => date('d/m/Y', strtotime($subscriber['created_at'])),
                'subscribe_time' => date('H:i', strtotime($subscriber['created_at'])),
            ]);

            return redirect()->route('subscribers')->with('success', 'Subscriber added successfully.');
        } else {
            return redirect()->route('subscribers')->with('error', 'Error adding subscriber.');
        }
    }

    public function destroy($id)
    {
        $apiKey = ApiKey::first();

        $response = Http::withHeaders([
            'X-MailerLite-ApiKey' => $apiKey->key,
        ])->delete("https://api.mailerlite.com/api/v2/subscribers/{$id}");

        if ($response->successful()) {
            Subscriber::where('email', $id)->delete();
            return response()->json(['success' => true]);
        } else {
            return response()->json(['error' => 'Failed to delete subscriber.']);
        }
    }
}
```

### 5.4. Create `EditSubscriberController`

**`app/Http/Controllers/EditSubscriberController.php`:**

```php
namespace App\Http\Controllers;

use Illuminate\Http\Request;
use Illuminate\Support\Facades\Http;
use App\Models\Subscriber;
use App\Models\ApiKey;

class EditSubscriberController extends Controller
{
    public function edit($id)
    {
        $apiKey = ApiKey::first();
        $subscriber = Subscriber::find($id);

        return view('editSubscriber', compact('subscriber', 'apiKey'));
    }

    public function update(Request $request, $id)
    {
        $request->validate([
            'name' => 'nullable|string',
            'country' => 'nullable|string',
        ]);

        $apiKey = ApiKey::first();

        $response = Http::withHeaders([
            'X-MailerLite-ApiKey' => $apiKey->key,
        ])->put("https://api.mailerlite.com/api/v2/subscribers/{$id}", [
            'name' => $request->name,
            'country' => $request->country,
        ]);

        if ($response->successful()) {
            Subscriber::where('email', $id)->update([
                'name' => $request->name,
                'country' => $request->country,
            ]);

            return redirect()->route('subscribers')->with('success', 'Subscriber updated successfully.');
        } else {
            return redirect()->route('subscribers')->with('error', 'Error updating subscriber.');
        }
    }
}
